      <strong>{{ text.empty }}</strong><p>{{ text.emptyCopy }}</p><div><button type="button" @click="$emit('reset')">{{ text.reset }}</button><NuxtLink v-if="canCreate" to="/admin/works/create">{{ text.create }}</NuxtLink></div>
    </div>
