            <th class="is-dynamic"><span class="ym-smart-list__head-title">{{ text.engagement }}</span><div class="ym-smart-list__head-control"><label><span class="sr-only">{{ text.metric }}</span><select :value="metric" @change="changeMetric"><option v-for="option in metricOptions" :key="option.value" :value="option.value">{{ option.label }}</option></select></label><button type="button" :aria-label="text.toggleDirection" @click="$emit('direction-change', 'metric')">{{ direction === 'desc' ? '↓' : '↑' }}</button></div></th>
            <th class="is-date"><span class="ym-smart-list__head-title">{{ text.dateHeading }}</span><div class="ym-smart-list__head-control"><label><span class="sr-only">{{ text.date }}</span><select :value="dateField" @change="changeDate"><option v-for="option in dateOptions" :key="option.value" :value="option.value">{{ option.label }}</option></select></label><button type="button" :aria-label="text.toggleDirection" @click="$emit('direction-change', 'date')">{{ direction === 'desc' ? '↓' : '↑' }}</button></div></th>
