            <td class="is-work">
              <WorksIndexInfoPopover :label="text.workInfo" :hint="text.openInfo" :close-label="text.close">
                <template #trigger><span class="ym-smart-list__work"><strong :dir="textDirection(work.title)">{{ work.title }}</strong><small><MediaIcon :type="work.media_type" />{{ mediaLabel(work.media_type) }}</small></span></template>
                <dl class="ym-smart-list__popover-list"><div><dt>{{ text.title }}</dt><dd>{{ work.title }}</dd></div><div><dt>{{ text.slug }}</dt><dd dir="ltr">{{ work.slug }}</dd></div><div><dt>{{ text.summary }}</dt><dd>{{ work.summary || text.none }}</dd></div><div><dt>{{ text.media }}</dt><dd>{{ mediaLabel(work.media_type) }}</dd></div><div><dt>{{ text.price }}</dt><dd>{{ work.price_amount || text.none }}</dd></div><div><dt>{{ text.delivery }}</dt><dd>{{ work.delivery_days === null ? text.none : formatNumber(work.delivery_days) }}</dd></div></dl>
              </WorksIndexInfoPopover>
            </td>
            <td class="is-status">
              <WorksIndexInfoPopover :label="text.statusInfo" :hint="text.openInfo" :close-label="text.close">
                <template #trigger><span class="ym-smart-list__status"><b :class="`is-${work.status}`">{{ statusLabel(work.status) }}</b><small>{{ visibilityLabel(work.visibility_status) }}<FeaturedIcon v-if="work.is_featured" /><PinIcon v-if="work.is_pinned" /></small></span></template>
                <dl class="ym-smart-list__popover-list"><div><dt>{{ text.workStatus }}</dt><dd>{{ statusLabel(work.status) }}</dd></div><div><dt>{{ text.visibility }}</dt><dd>{{ visibilityLabel(work.visibility_status) }}</dd></div><div><dt>{{ text.featured }}</dt><dd>{{ yesNo(work.is_featured) }}</dd></div><div><dt>{{ text.pinned }}</dt><dd>{{ yesNo(work.is_pinned) }}</dd></div></dl>
              </WorksIndexInfoPopover>
