                <div class="ym-smart-list__taxonomy-detail"><strong>{{ categoryLabel(work) }}</strong><small v-if="work.taxonomy.category">{{ work.taxonomy.category.is_active ? text.active : text.disabled }}</small><p v-if="work.taxonomy.tags === null">{{ text.unavailable }}</p><p v-else-if="work.taxonomy.tags.length === 0">{{ text.noTags }}</p><ul v-else><li v-for="tag in work.taxonomy.tags" :key="tag.id" :class="{ 'is-disabled': !tag.is_active }">{{ taxonomyName(tag) }} <small v-if="!tag.is_active">{{ text.disabled }}</small></li></ul></div>
              </WorksIndexInfoPopover>
