                <dl class="ym-smart-list__popover-list"><div><dt>{{ text.views }}</dt><dd>{{ formatNumber(work.views_count) }}</dd></div><div><dt>{{ text.likes }}</dt><dd>{{ formatNumber(work.likes_count) }}</dd></div><div :class="{ 'is-alert': work.reports_count > 0 }"><dt>{{ text.reports }}</dt><dd>{{ formatNumber(work.reports_count) }}</dd></div></dl>
              </WorksIndexInfoPopover>
