                <dl class="ym-smart-list__popover-list"><div v-for="option in dateOptions" :key="option.value"><dt>{{ option.label }}</dt><dd class="is-date-value">{{ formatDateTime(work[option.value]) }}</dd></div></dl>
              </WorksIndexInfoPopover>
