            <td class="is-actions"><ActionButtons :work="work" :can-edit="canEditWork(work)" :can-details="canViewDetails" :can-taxonomy="canManageTaxonomy" :text="text" @details="$emit('details', work)" @taxonomy="$emit('taxonomy', work)" /></td>
          </tr></tbody>
        </table>
      </div>

      <div class="ym-smart-list__mobile">
        <article v-for="work in items" :key="work.id">
          <header><input v-if="canSelect" type="checkbox" :checked="isSelected(work.id)" :disabled="!isSelected(work.id) && selectionAtLimit" :aria-label="text.selectWork(work.title)" @change="$emit('toggle-work', work)" /><div><strong :dir="textDirection(work.title)">{{ work.title }}</strong></div><span class="ym-smart-list__status"><b :class="`is-${work.status}`">{{ statusLabel(work.status) }}</b></span></header>
          <div class="ym-smart-list__mobile-meta"><span><MediaIcon :type="work.media_type" />{{ mediaLabel(work.media_type) }}</span><span>{{ visibilityLabel(work.visibility_status) }}<FeaturedIcon v-if="work.is_featured" /><PinIcon v-if="work.is_pinned" /></span></div>
          <dl><div><dt>{{ text.team }}</dt><dd class="is-team-lines"><span>{{ text.designer }}: {{ work.designer?.name || text.unassigned }}</span><span>{{ text.reviewer }}: {{ work.reviewer?.name || text.unassigned }}</span></dd></div><div><dt>{{ text.taxonomy }}</dt><dd>{{ categoryLabel(work) }} · {{ tagsSummary(work) }}</dd></div><div><dt>{{ metricLabel }}</dt><dd class="is-number">{{ formatNumber(work[metric]) }}</dd></div><div><dt>{{ dateLabel }}</dt><dd class="is-date-value">{{ formatDate(work[dateField]) }}</dd></div></dl>
          <footer><WorksIndexInfoPopover :label="text.moreInfo" :hint="text.openInfo" :close-label="text.close"><template #trigger><span class="ym-smart-list__more">{{ text.moreInfo }}</span></template><dl class="ym-smart-list__popover-list"><div><dt>{{ text.views }}</dt><dd>{{ formatNumber(work.views_count) }}</dd></div><div><dt>{{ text.likes }}</dt><dd>{{ formatNumber(work.likes_count) }}</dd></div><div><dt>{{ text.reports }}</dt><dd>{{ formatNumber(work.reports_count) }}</dd></div><div v-for="option in dateOptions" :key="option.value"><dt>{{ option.label }}</dt><dd class="is-date-value">{{ formatDateTime(work[option.value]) }}</dd></div></dl></WorksIndexInfoPopover><ActionButtons :work="work" :can-edit="canEditWork(work)" :can-details="canViewDetails" :can-taxonomy="canManageTaxonomy" :text="text" @details="$emit('details', work)" @taxonomy="$emit('taxonomy', work)" /></footer>
        </article>
      </div>

      <footer class="ym-smart-list__pagination"><span :aria-label="footerAriaLabel">{{ summary ? text.showing(formatNumber(summary.visible_on_page), formatNumber(summary.total_filtered)) : text.summaryUnavailable }}</span><nav :aria-label="text.pagination"><button type="button" :disabled="loading || pagination.current_page <= 1" @click="$emit('page', pagination.current_page - 1)">{{ text.previous }}</button><b>{{ text.pageOf(formatNumber(pagination.current_page), formatNumber(pagination.last_page)) }}</b><button type="button" :disabled="loading || pagination.current_page >= pagination.last_page" @click="$emit('page', pagination.current_page + 1)">{{ text.next }}</button></nav></footer>
    </template>
  </section>
</template>

<script setup lang="ts">
import { computed, defineComponent, h, watch } from 'vue'
import WorksIndexFloatingOverlay from './WorksIndexFloatingOverlay.vue'
import WorksIndexInfoPopover from './WorksIndexInfoPopover.vue'
import { formatYmDate, formatYmDateTime, formatYmNumber } from '~/utils/ymFormatting'

type MetricKey = 'views_count' | 'likes_count' | 'reports_count'
type DateKey = 'created_at' | 'updated_at' | 'submitted_at' | 'reviewed_at' | 'approved_at' | 'published_at' | 'rejected_at' | 'hidden_at' | 'archived_at'
interface Entity { id: number; name_ar: string; name_en: string; is_active: boolean }
interface WorkItem { id: number; title: string; slug: string; summary: string | null; status: string; visibility_status: string; media_type: string | null; price_amount: string | null; delivery_days: number | null; designer: { id: number; name: string } | null; reviewer: { id: number; name: string } | null; category_id: number | null; is_featured: boolean; is_pinned: boolean; reports_count: number; views_count: number; likes_count: number; created_at: string | null; updated_at: string | null; submitted_at: string | null; reviewed_at: string | null; approved_at: string | null; published_at: string | null; rejected_at: string | null; hidden_at: string | null; archived_at: string | null; taxonomy: { category: Entity | null; category_tracking: { is_legacy_unmapped: boolean; is_uncategorized: boolean } | null; tags: Entity[] | null } }
interface Summary { total_filtered: number; visible_on_page: number; published_filtered: number; review_cycle_filtered: number; reported_filtered: number }
interface TextCopy { [key: string]: any }
const props = defineProps<{ locale: 'ar' | 'en'; items: WorkItem[]; pagination: { current_page: number; total: number; last_page: number }; summary: Summary | null; summaryWarning: string | null; loading: boolean; updating: boolean; error: string | null; metric: MetricKey; dateField: DateKey; sort: string; direction: 'asc' | 'desc'; canSelect: boolean; selectedIds: number[]; selectionAtLimit: boolean; canViewDetails: boolean; canManageTaxonomy: boolean; canCreate: boolean; canEditWork: (work: WorkItem) => boolean }>()
const copies = {
  ar: { loading: 'جارٍ تحميل الأعمال', loadingCopy: 'يتم جلب أحدث نتيجة مطابقة للفلاتر.', updating: 'جارٍ تحديث النتائج مع إبقاء آخر بيانات متناسقة…', error: 'تعذر تحميل قائمة الأعمال', retry: 'إعادة المحاولة', empty: 'لا توجد أعمال مطابقة.', emptyCopy: 'جرّب إعادة ضبط الفلاتر أو إنشاء عمل جديد.', reset: 'إعادة ضبط الفلاتر', create: 'إنشاء عمل جديد', selectPage: 'تحديد الصفحة الحالية', selectWork: (title: string) => `تحديد العمل ${title}`, work: 'العمل', status: 'الحالة', team: 'الفريق', taxonomy: 'التصنيف والوسوم', engagement: 'التفاعل', metric: 'مؤشر التفاعل', date: 'نوع التاريخ', dateHeading: 'التاريخ', direction: 'اتجاه الفرز', descending: 'تنازلي', ascending: 'تصاعدي', viewControls: 'أدوات عرض البطاقات', toggleDirection: 'تغيير اتجاه الفرز', actions: 'الإجراءات', workInfo: 'معلومات العمل', statusInfo: 'معلومات الحالة', teamInfo: 'معلومات الفريق', taxonomyInfo: 'معلومات التصنيف والوسوم', engagementInfo: 'تفاصيل التفاعل', dateInfo: 'جميع تواريخ العمل', moreInfo: 'عرض التفاصيل', openInfo: 'عرض التفاصيل', close: 'إغلاق', title: 'العنوان', slug: 'المعرّف النصي للرابط', summary: 'الملخص', media: 'نوع الوسائط', price: 'السعر', delivery: 'مدة التسليم بالأيام', none: 'غير متوفر', visibility: 'الظهور', workStatus: 'حالة العمل', featured: 'مميز', pinned: 'مثبت', designer: 'المصمم', reviewer: 'المراجع', unassigned: 'غير معيّن', unavailable: 'غير متاح حسب الصلاحية', uncategorized: 'غير مصنف', active: 'فعال', disabled: 'معطل', noTags: 'دون وسوم', tagsCount: (count: number) => `${formatYmNumber(count, props.locale)} وسوم`, views: 'المشاهدات', likes: 'الإعجابات', reports: 'البلاغات', hasReports: 'يوجد بلاغ واحد أو أكثر', image: 'صورة', video: 'فيديو', gallery: 'معرض صور', unknownMedia: 'غير محدد', public: 'عام', hidden: 'مخفي', yes: 'نعم', no: 'لا', edit: 'تحرير العمل', details: 'عرض التفاصيل', manageTaxonomy: 'إدارة التصنيف والوسوم', showing: (visible: string, total: string) => `عرض ${visible} من أصل ${total}`, summaryUnavailable: 'عرض — من أصل —', pagination: 'التنقل بين صفحات الأعمال', previous: 'السابق', next: 'التالي', pageOf: (page: string, last: string) => `الصفحة ${page} من ${last}` },
  en: { loading: 'Loading works', loadingCopy: 'Fetching the latest result matching the filters.', updating: 'Updating results while keeping the last consistent data…', error: 'Could not load works', retry: 'Retry', empty: 'No matching works.', emptyCopy: 'Reset the filters or create a new work.', reset: 'Reset filters', create: 'Create new work', selectPage: 'Select current page', selectWork: (title: string) => `Select ${title}`, work: 'Work', status: 'Status', team: 'Team', taxonomy: 'Category and tags', engagement: 'Engagement', metric: 'Engagement metric', date: 'Date type', dateHeading: 'Date', direction: 'Sort direction', descending: 'Descending', ascending: 'Ascending', viewControls: 'Card view controls', toggleDirection: 'Toggle sort direction', actions: 'Actions', workInfo: 'Work information', statusInfo: 'Status information', teamInfo: 'Team information', taxonomyInfo: 'Category and tag information', engagementInfo: 'Engagement details', dateInfo: 'All work dates', moreInfo: 'View details', openInfo: 'View details', close: 'Close', title: 'Title', slug: 'Slug', summary: 'Summary', media: 'Media type', price: 'Price', delivery: 'Delivery days', none: 'Unavailable', visibility: 'Visibility', workStatus: 'Work status', featured: 'Featured', pinned: 'Pinned', designer: 'Designer', reviewer: 'Reviewer', unassigned: 'Unassigned', unavailable: 'Unavailable for this permission scope', uncategorized: 'Uncategorized', active: 'Active', disabled: 'Disabled', noTags: 'No tags', tagsCount: (count: number) => `${formatYmNumber(count, props.locale)} tags`, views: 'Views', likes: 'Likes', reports: 'Reports', hasReports: 'One or more reports exist', image: 'Image', video: 'Video', gallery: 'Gallery', unknownMedia: 'Unspecified', public: 'Public', hidden: 'Hidden', yes: 'Yes', no: 'No', edit: 'Edit work', details: 'View details', manageTaxonomy: 'Manage category and tags', showing: (visible: string, total: string) => `Showing ${visible} of ${total}`, summaryUnavailable: 'Showing — of —', pagination: 'Works pagination', previous: 'Previous', next: 'Next', pageOf: (page: string, last: string) => `Page ${page} of ${last}` }
} as const
const text = computed(() => copies[props.locale] as TextCopy)
const metricOptions = computed(() => [{ value: 'views_count' as const, label: text.value.views }, { value: 'likes_count' as const, label: text.value.likes }, { value: 'reports_count' as const, label: text.value.reports }])
const dateOptions = computed(() => [{ value: 'created_at' as const, label: props.locale === 'ar' ? 'تاريخ الإنشاء' : 'Created at' }, { value: 'updated_at' as const, label: props.locale === 'ar' ? 'آخر تحديث' : 'Last updated' }, { value: 'submitted_at' as const, label: props.locale === 'ar' ? 'تاريخ الإرسال' : 'Submitted at' }, { value: 'reviewed_at' as const, label: props.locale === 'ar' ? 'تاريخ المراجعة' : 'Reviewed at' }, { value: 'approved_at' as const, label: props.locale === 'ar' ? 'تاريخ الاعتماد' : 'Approved at' }, { value: 'published_at' as const, label: props.locale === 'ar' ? 'تاريخ النشر' : 'Published at' }, { value: 'rejected_at' as const, label: props.locale === 'ar' ? 'تاريخ الرفض' : 'Rejected at' }, { value: 'hidden_at' as const, label: props.locale === 'ar' ? 'تاريخ الإخفاء' : 'Hidden at' }, { value: 'archived_at' as const, label: props.locale === 'ar' ? 'تاريخ الأرشفة' : 'Archived at' }])
const metricLabel = computed(() => metricOptions.value.find(option => option.value === props.metric)?.label || '')
const dateLabel = computed(() => dateOptions.value.find(option => option.value === props.dateField)?.label || '')
const currentControlKind = computed<'metric' | 'date'>(() => props.sort === props.metric ? 'metric' : 'date')
const footerAriaLabel = computed(() => props.summary
  ? text.value.showing(formatNumber(props.summary.visible_on_page), formatNumber(props.summary.total_filtered))
  : text.value.summaryUnavailable)
const allSelected = computed(() => props.items.length > 0 && props.items.every(work => props.selectedIds.includes(work.id)))
const isSelected = (id: number) => props.selectedIds.includes(id)
const formatNumber = (value: number) => formatYmNumber(value, props.locale)
const formatDate = (value: string | null) => formatYmDate(value, props.locale)
const formatDateTime = (value: string | null) => formatYmDateTime(value, props.locale)
function textDirection(value: string): 'rtl' | 'ltr' { return /[\u0600-\u06FF]/.test(value) ? 'rtl' : 'ltr' }
function mediaLabel(value: string | null): string { return value === 'image' ? text.value.image : value === 'video' ? text.value.video : value === 'gallery' ? text.value.gallery : text.value.unknownMedia }
function visibilityLabel(value: string): string { return value === 'public' ? text.value.public : text.value.hidden }
function yesNo(value: boolean): string { return value ? text.value.yes : text.value.no }
function statusLabel(value: string): string { const ar: Record<string, string> = { draft: 'مسودة', submitted: 'قيد المراجعة', in_review: 'تحت المراجعة', changes_requested: 'تعديلات مطلوبة', approved: 'معتمد', published: 'منشور', rejected: 'مرفوض', hidden: 'مخفي', archived: 'مؤرشف' }; const en: Record<string, string> = { draft: 'Draft', submitted: 'Submitted', in_review: 'In review', changes_requested: 'Changes requested', approved: 'Approved', published: 'Published', rejected: 'Rejected', hidden: 'Hidden', archived: 'Archived' }; return (props.locale === 'ar' ? ar : en)[value] || value }
function taxonomyName(entity: Entity): string { return props.locale === 'ar' ? entity.name_ar : entity.name_en }
function categoryLabel(work: WorkItem): string { if (work.taxonomy.category) return taxonomyName(work.taxonomy.category); if (work.taxonomy.category_tracking?.is_uncategorized) return text.value.uncategorized; if (work.taxonomy.category_tracking?.is_legacy_unmapped) return props.locale === 'ar' ? 'تصنيف قديم' : 'Legacy category'; return text.value.unavailable }
function tagsSummary(work: WorkItem): string { if (work.taxonomy.tags === null) return text.value.unavailable; return work.taxonomy.tags.length ? text.value.tagsCount(work.taxonomy.tags.length) : text.value.noTags }
function changeMetric(event: Event): void { const value = (event.target as HTMLSelectElement).value as MetricKey; if (metricOptions.value.some(option => option.value === value)) emit('metric-change', value) }
function changeDate(event: Event): void { const value = (event.target as HTMLSelectElement).value as DateKey; if (dateOptions.value.some(option => option.value === value)) emit('date-change', value) }
const emit = defineEmits<{ retry: []; reset: []; 'toggle-page': []; 'toggle-work': [work: WorkItem]; 'metric-change': [metric: MetricKey]; 'date-change': [date: DateKey]; 'direction-change': [kind: 'metric' | 'date']; details: [work: WorkItem]; taxonomy: [work: WorkItem]; page: [page: number] }>()
const icon = (paths: string[]) => defineComponent({ setup: () => () => h('svg', { viewBox: '0 0 24 24', 'aria-hidden': 'true' }, paths.map(d => h('path', { d }))) })
